17652   /// Calculate the cost of a reduction.
17653   InstructionCost getReductionCost(TargetTransformInfo *TTI,
17654                                    ArrayRef<Value *> ReducedVals,
17655                                    bool IsCmpSelMinMax, unsigned ReduxWidth,
17656                                    FastMathFlags FMF) {
17657     TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;
17658     Type *ScalarTy = ReducedVals.front()->getType();
17659     FixedVectorType *VectorTy = FixedVectorType::get(ScalarTy, ReduxWidth);
17660     InstructionCost VectorCost = 0, ScalarCost;
17661     // If all of the reduced values are constant, the vector cost is 0, since
17662     // the reduction value can be calculated at the compile time.
17663     bool AllConsts = allConstant(ReducedVals);
17664     auto EvaluateScalarCost = [&](function_ref<InstructionCost()> GenCostFn) {
17665       InstructionCost Cost = 0;
17666       // Scalar cost is repeated for N-1 elements.
17667       int Cnt = ReducedVals.size();
17668       for (Value *RdxVal : ReducedVals) {
17669         if (Cnt == 1)
17670           break;
17671         --Cnt;
17672         if (RdxVal->hasNUsesOrMore(IsCmpSelMinMax ? 3 : 2)) {
17673           Cost += GenCostFn();
17674           continue;
17675         }
17676         InstructionCost ScalarCost = 0;
17677         for (User *U : RdxVal->users()) {
17678           auto *RdxOp = cast<Instruction>(U);
17679           if (hasRequiredNumberOfUses(IsCmpSelMinMax, RdxOp)) {
17680             ScalarCost += TTI->getInstructionCost(RdxOp, CostKind);
17681             continue;
17682           }
17683           ScalarCost = InstructionCost::getInvalid();
17684           break;
17685         }
17686         if (ScalarCost.isValid())
17687           Cost += ScalarCost;
17688         else
17689           Cost += GenCostFn();
17690       }
17691       return Cost;
17692     };
17693     switch (RdxKind) {
17694     case RecurKind::Add:
17695     case RecurKind::Mul:
17696     case RecurKind::Or:
17697     case RecurKind::And:
17698     case RecurKind::Xor:
17699     case RecurKind::FAdd:
17700     case RecurKind::FMul: {
17701       unsigned RdxOpcode = RecurrenceDescriptor::getOpcode(RdxKind);
17702       if (!AllConsts)
17703         VectorCost =
17704             TTI->getArithmeticReductionCost(RdxOpcode, VectorTy, FMF, CostKind);
17705       ScalarCost = EvaluateScalarCost([&]() {
17706         return TTI->getArithmeticInstrCost(RdxOpcode, ScalarTy, CostKind);
17707       });
17708       break;
17709     }
17710     case RecurKind::FMax:
17711     case RecurKind::FMin:
17712     case RecurKind::FMaximum:
17713     case RecurKind::FMinimum:
17714     case RecurKind::SMax:
17715     case RecurKind::SMin:
17716     case RecurKind::UMax:
17717     case RecurKind::UMin: {
17718       Intrinsic::ID Id = getMinMaxReductionIntrinsicOp(RdxKind);
17719       if (!AllConsts)
17720         VectorCost = TTI->getMinMaxReductionCost(Id, VectorTy, FMF, CostKind);
17721       ScalarCost = EvaluateScalarCost([&]() {
17722         IntrinsicCostAttributes ICA(Id, ScalarTy, {ScalarTy, ScalarTy}, FMF);
17723         return TTI->getIntrinsicInstrCost(ICA, CostKind);
17724       });
17725       break;
17726     }
17727     default:
17728       llvm_unreachable("Expected arithmetic or min/max reduction operation");
17729     }
17730 
17731     LLVM_DEBUG(dbgs() << "SLP: Adding cost " << VectorCost - ScalarCost
17732                       << " for reduction of " << shortBundleName(ReducedVals)
17733                       << " (It is a splitting reduction)\n");
17734     return VectorCost - ScalarCost;
17735   }
